function calculateEligibility(inputs) {
  const age = inputs.age;
  const yearsWorked = inputs.yearsWorked;
  const averageAnnualIncome = inputs.averageAnnualIncome;
  const functionalLimitationScore = inputs.functionalLimitationScore;
  const hasVeteranStatus = inputs.hasVeteranStatus;
  const serviceConnectedDisabilityRating = inputs.serviceConnectedDisabilityRating || 0;
  const numberOfDependents = inputs.numberOfDependents;
  const currentHouseholdIncome = inputs.currentHouseholdIncome;
  const currentHouseholdAssets = inputs.currentHouseholdAssets;

  let eligibilityScore = 0;
  let estimatedMonthlyBenefit = 0;
  let programRecommendations = [];

  // --- Constants (simplified for estimation) ---
  const SSDI_MIN_WORK_CREDITS = 20; // Roughly 5 years for younger, more for older
  const SSDI_ELIGIBLE_AGE_MIN = 21; // Generally, younger than 21 requires fewer credits
  const SSDI_MAX_BENEFIT = 3822; // As of 2024
  const SSI_FBR = 943; // Federal Benefit Rate 2024 (individual)
  const SSI_ASSET_LIMIT_INDIVIDUAL = 2000;
  const SSI_ASSET_LIMIT_COUPLE = 3000; // Simplified to individual for this tool
  const SSI_INCOME_DISREGARD = 85; // General income disregard

  // --- 1. Assess Functional Limitation Severity ---
  let medicalSeverityFactor = 0;
  if (functionalLimitationScore >= 70) {
    medicalSeverityFactor = 0.5; // Very severe
  } else if (functionalLimitationScore >= 50) {
    medicalSeverityFactor = 0.3; // Significantly severe
  } else if (functionalLimitationScore >= 30) {
    medicalSeverityFactor = 0.1; // Moderate
  }
  eligibilityScore += functionalLimitationScore * 0.4; // 40% impact

  // --- 2. SSDI (Social Security Disability Insurance) Assessment ---
  let potentialSSDI = 0;
  let ssdiWorkCredits = Math.min(yearsWorked * 4, 40); // Max 40 credits needed for fully insured
  let requiredWorkCreditsForAge = 0;

  if (age < 24) {
    requiredWorkCreditsForAge = 6;
  } else if (age >= 24 && age <= 31) {
    requiredWorkCreditsForAge = Math.floor((age - 21) / 2) * 2 + 6; // Roughly 1 credit per year worked
  } else {
    requiredWorkCreditsForAge = Math.min(20, Math.floor((age - 21) / 2) * 2);
  }

  requiredWorkCreditsForAge = Math.max(requiredWorkCreditsForAge, SSDI_MIN_WORK_CREDITS); // Ensure minimum credits

  const hasSufficientWorkCredits = ssdiWorkCredits >= requiredWorkCreditsForAge;

  if (hasSufficientWorkCredits && functionalLimitationScore >= 50 && age < 67) {
    programRecommendations.push('SSDI');
    eligibilityScore += 30; // Boost for SSDI eligibility
    // Simplified SSDI benefit calculation: AIME approximation
    let AIME = Math.min(averageAnnualIncome / 12, 10000); // Capped AIME for simplicity
    potentialSSDI = Math.min(0.9 * AIME, SSDI_MAX_BENEFIT); // Progressive formula
    potentialSSDI += (numberOfDependents > 0 ? Math.min(numberOfDependents * 100, 500) : 0); // Dependent benefits
    potentialSSDI = Math.min(potentialSSDI, SSDI_MAX_BENEFIT);
  }
  // Max SSDI is generally ~150% of PIA for family benefits. Let's cap the dependent boost.
  potentialSSDI = Math.min(potentialSSDI, SSDI_MAX_BENEFIT * 1.5); 

  // --- 3. SSI (Supplemental Security Income) Assessment ---
  let potentialSSI = 0;
  // Check income and assets, consider individual FBR and asset limits
  const effectiveIncome = Math.max(0, currentHouseholdIncome - SSI_INCOME_DISREGARD); // Rough income disregard
  const isLowIncome = effectiveIncome < SSI_FBR * 1.5; // Slightly higher threshold for consideration
  const isLowAsset = currentHouseholdAssets <= SSI_ASSET_LIMIT_INDIVIDUAL;

  if (isLowIncome && isLowAsset && functionalLimitationScore >= 50) {
    programRecommendations.push('SSI');
    eligibilityScore += 20; // Boost for SSI eligibility
    potentialSSI = Math.max(0, SSI_FBR - effectiveIncome); // Benefit reduced by countable income
  }

  // --- 4. VA Disability Assessment ---
  let potentialVADisability = 0;
  if (hasVeteranStatus === 'Yes' && serviceConnectedDisabilityRating > 0 && functionalLimitationScore >= 30) {
    programRecommendations.push('VA Disability');
    eligibilityScore += 25; // Boost for VA eligibility
    // Simplified VA benefit calculation: highly variable, estimate based on rating
    potentialVADisability = (serviceConnectedDisabilityRating / 100) * 3500; // Max VA benefit is high, this is a rough avg
    potentialVADisability += (numberOfDependents > 0 ? numberOfDependents * 150 : 0); // Some dependent benefits
  }

  // --- 5. Overall Eligibility and Benefit Aggregation ---
  // General eligibility score based on weighted factors
  eligibilityScore += (yearsWorked / 45) * 10; // 10% for work history
  eligibilityScore += (age / 67) * 5; // 5% for age curve
  if (hasVeteranStatus === 'Yes') eligibilityScore += 10; // 10% for veteran status

  eligibilityScore = Math.min(100, Math.max(0, eligibilityScore));

  let potentialEligibilityText = 'Unlikely';
  if (eligibilityScore >= 75 && medicalSeverityFactor > 0.3) {
    potentialEligibilityText = 'High Potential';
  } else if (eligibilityScore >= 50 && medicalSeverityFactor > 0.1) {
    potentialEligibilityText = 'Moderate Potential';
  } else if (eligibilityScore >= 25) {
    potentialEligibilityText = 'Low Potential';
  }

  // Determine estimated monthly benefit, prioritize higher benefits but avoid stacking full amounts unrealistically
  // This tool provides an estimate of the *highest potential* benefit from *one* primary source, or a sensible combination.
  if (programRecommendations.includes('SSDI') && potentialSSDI > estimatedMonthlyBenefit) {
    estimatedMonthlyBenefit = potentialSSDI;
  }
  if (programRecommendations.includes('VA Disability') && potentialVADisability > estimatedMonthlyBenefit) {
    estimatedMonthlyBenefit = potentialVADisability;
  }
  // SSI usually supplements if other benefits are low, or is the primary for low-income/asset individuals.
  // If primarily SSI eligible and other benefits are low, SSI might be the main one.
  if (programRecommendations.includes('SSI') && (estimatedMonthlyBenefit < SSI_FBR * 1.2 || !programRecommendations.includes('SSDI'))) {
    estimatedMonthlyBenefit = Math.max(estimatedMonthlyBenefit, potentialSSI); // Add SSI if not covered or very low
  }

  // Cap estimated benefit at a reasonable maximum for general disability benefits
  estimatedMonthlyBenefit = Math.min(estimatedMonthlyBenefit, 5000); // General cap for combined estimate

  // Handle edge cases: No eligibility means $0 benefit
  if (programRecommendations.length === 0) {
    estimatedMonthlyBenefit = 0;
    potentialEligibilityText = 'Unlikely';
  }

  return {
    potentialEligibility: potentialEligibilityText,
    estimatedMonthlyBenefit: estimatedMonthlyBenefit,
    programRecommendations: programRecommendations.length > 0 ? programRecommendations.join(', ') : 'No specific programs identified. Consult a professional.'
  };
}
